create_matrix &lt;- function(r=5, c=5){

  stor_mat &lt;- matrix(, nrow = r, ncol = c)

  for (i in 1:r){
    for (j in 1:c){

       stor_mat[i,j] &lt;- i*j

    }
  }
  return(stor_mat)
}

